<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Sorting Visualizer</title>
<style>
  :root {
    --bg: #12141a;
    --panel: #1b1e27;
    --bar: #4f8cff;
    --bar-active: #ffb347;
    --bar-done: #4fd47a;
    --text: #e6e9f0;
  }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    background: var(--bg);
    color: var(--text);
    font-family: system-ui, sans-serif;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 24px;
    padding: 24px;
  }
  h1 { font-size: 1.3rem; font-weight: 600; letter-spacing: .03em; }
  #bars {
    display: flex;
    align-items: flex-end;
    gap: 3px;
    width: min(90vw, 900px);
    height: 320px;
    background: var(--panel);
    border-radius: 10px;
    padding: 14px;
    border: 1px solid #2a2e3b;
  }
  .bar {
    flex: 1;
    background: var(--bar);
    border-radius: 3px 3px 0 0;
    transition: height 60ms linear, background 100ms linear;
    min-width: 2px;
  }
  .bar.active { background: var(--bar-active); }
  .bar.done { background: var(--bar-done); }
  .controls { display: flex; gap: 12px; }
  button {
    background: #2a2e3b;
    color: var(--text);
    border: 1px solid #3a3f50;
    border-radius: 8px;
    padding: 10px 22px;
    font-size: 1rem;
    cursor: pointer;
    transition: background 120ms;
  }
  button:hover { background: #363b4d; }
  button:disabled { opacity: .5; cursor: default; }
</style>
</head>
<body>
  <h1>Sorting Algorithm Visualizer — Bubble Sort</h1>
  <div id="bars"></div>
  <div class="controls">
    <button id="sort">Sort</button>
    <button id="shuffle">Shuffle</button>
    <button id="reset">Reset</button>
  </div>

<script>
(function () {
  const N = 40;
  const barsEl = document.getElementById('bars');

  let arr = [];
  // Bubble sort state
  let i = 0;          // current comparison index within the pass
  let end = 0;        // unsorted region ends here (exclusive)
  let swappedInPass = false;
  let finished = false;
  let animTimer = null;

  function resetSortState() {
    i = 0;
    end = arr.length;
    swappedInPass = false;
    finished = isAscending(arr);
  }

  function isAscending(a) {
    for (let k = 1; k < a.length; k++) {
      if (a[k - 1] > a[k]) return false;
    }
    return true;
  }

  function render(activeA, activeB) {
    barsEl.innerHTML = '';
    const max = Math.max(...arr, 1);
    const done = isAscending(arr);
    for (let k = 0; k < arr.length; k++) {
      const bar = document.createElement('div');
      bar.className = 'bar';
      if (done) bar.classList.add('done');
      else if (k === activeA || k === activeB) bar.classList.add('active');
      bar.style.height = Math.max(2, (arr[k] / max) * 100) + '%';
      bar.title = String(arr[k]);
      barsEl.appendChild(bar);
    }
  }

  // One comparison step of bubble sort. Returns true when fully sorted.
  function sortStep() {
    if (finished || isAscending(arr)) {
      finished = true;
      render();
      return true;
    }
    if (end <= 1) {
      finished = true;
      render();
      return true;
    }
    if (i >= end - 1) {
      // pass complete
      if (!swappedInPass) {
        finished = true;
        render();
        return true;
      }
      end--;
      i = 0;
      swappedInPass = false;
      if (end <= 1) {
        finished = true;
        render();
        return true;
      }
    }
    const a = i, b = i + 1;
    if (arr[a] > arr[b]) {
      const t = arr[a]; arr[a] = arr[b]; arr[b] = t;
      swappedInPass = true;
    }
    i++;
    render(a, b);
    if (isAscending(arr) && !swappedRemaining()) {
      // cheap early check: only mark finished when truly sorted
    }
    if (isAscending(arr) && end <= 1) finished = true;
    return finished;
  }

  function swappedRemaining() { return swappedInPass; }

  function randomArray() {
    const a = [];
    for (let k = 0; k < N; k++) a.push(Math.floor(Math.random() * 95) + 5);
    return a;
  }

  function shuffleInPlace(a) {
    for (let k = a.length - 1; k > 0; k--) {
      const j = Math.floor(Math.random() * (k + 1));
      const t = a[k]; a[k] = a[j]; a[j] = t;
    }
  }

  function stopAnimation() {
    if (animTimer !== null) {
      clearInterval(animTimer);
      animTimer = null;
    }
  }

  function setArray(a) {
    stopAnimation();
    arr = a.map(Number);
    resetSortState();
    render();
  }

  // Controls
  document.getElementById('sort').addEventListener('click', () => {
    stopAnimation();
    animTimer = setInterval(() => {
      const done = sortStep();
      if (done) stopAnimation();
    }, 12);
  });

  document.getElementById('shuffle').addEventListener('click', () => {
    stopAnimation();
    shuffleInPlace(arr);
    resetSortState();
    render();
  });

  document.getElementById('reset').addEventListener('click', () => {
    setArray(randomArray());
  });

  // Public API
  window.viz = {
    array() { return arr.slice(); },
    setArray(a) { setArray(a); },
    sortStep() { return sortStep(); },
    sorted() { return isAscending(arr); },
  };

  setArray(randomArray());
})();
</script>
</body>
</html>
